mutation {
  ingestOntology(input: {
    url: "https://raw.githubusercontent.com/Skitionek/Mozg/main/examples/blog.ttl"
    format: turtle
  }) {
    tripleCount
    classes { iri label subClassOf }
    objectProperties { iri label domain range relationType }
    dataProperties { iri label domain range graphqlType }
    generatedTypeDefs
  }
}

{
  generateSchema(input: {
    url: "https://raw.githubusercontent.com/Skitionek/Mozg/main/examples/blog.ttl"
    format: turtle
  }) {
    tripleCount
    generatedTypeDefs
    generatedTypes { typeName fields relations }
  }
}
